import android.app.Activity
import android.content.Context
import com.android.billingclient.api.*

class PaymentModule(private val activity: Activity) {

    private var billingClient: BillingClient? = null
    var isReadyToPurchase = false

    fun init() {
        billingClient = BillingClient.newBuilder(activity)
            .enablePendingPurchases()
            .setListener { billingResult, purchases ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK && purchases != null) {
                    for (purchase in purchases) {
                        handlePurchase(purchase)
                    }
                }
            }
            .build()
        startServiceConnection(Runnable { querySkuDetails() })
    }

    private fun startServiceConnection(onServiceConnected: Runnable) {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                isReadyToPurchase = billingResult.responseCode == BillingClient.BillingResponseCode.OK
                if (isReadyToPurchase) onServiceConnected.run()
            }

            override fun onBillingServiceDisconnected() {
                isReadyToPurchase = false
            }
        })
    }

    private fun querySkuDetails() {
        val params = SkuDetailsParams.newBuilder().setSkusList(listOf("sku_id_1", "sku_id_2"))
            .setType(BillingClient.SkuType.INAPP).build()

        billingClient?.querySkuDetailsAsync(params) { _, _ -> }
    }

    fun makePurchase(skuDetails: SkuDetails) {
        val flowParams = BillingFlowParams.newBuilder().setSkuDetails(skuDetails).build()

        billingClient?.launchBillingFlow(activity, flowParams)
    }

    private fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            if (!purchase.isAcknowledged) {
                val ackPurchaseParams = AcknowledgePurchaseParams.newBuilder()
                    .setPurchaseToken(purchase.purchaseToken).build()

                billingClient?.acknowledgePurchase(ackPurchaseParams) { _ -> }
            }
        }
    }
}